Frame then updateGearInventoryDisplay(contentFrame, "") end end end) end end) if GearRemotes then local UpdateGearLuck = GearRemotes:FindFirstChild("UpdateGearLuck") if UpdateGearLuck then UpdateGearLuck.OnClientEvent:Connect(function() task.delay(0.5, function() if currentActiveTab == "gears" and currentPopup and currentPopup.Name == "InventoryPopupGui" then local contentFrame = currentPopup:FindFirstChild("ContentFrame") if contentFrame then updateGearInventoryDisplay(contentFrame, "") end end end) end) end end end setupAutoRefresh() setupGearSystemMonitoring() _G.RefreshGearIcons = function() if currentActiveTab == "gears" and currentPopup and currentPopup.Name == "InventoryPopupGui" then closeCurrentPopup() task.delay(0.1, showInventoryPopup) end end print("IconCreator loaded successfully with complete gear system integration!")

