quested by player " .. player.Name .. ": " .. itemName) return end print("?? AddBrainrotItem event: " .. player.Name .. " -> " .. itemName) local updatedInventory = addItemToInventory(player.UserId, itemName) updateInventoryEvent:FireClient(player, updatedInventory) end) getInventoryFunction.OnServerInvoke = function(player) return playerInventories[player.UserId] or {} end removeItemEvent.OnServerEvent:Connect(function(player, itemName, amount) if type(itemName) ~= "string" or itemName == "" then return end local updatedInventory = removeItemFromInventory(player.UserId, itemName, amount) updateInventoryEvent:FireClient(player, updatedInventory) end) RemoveItemFunc.OnServerInvoke = function(player, itemName, amount) if not player or not player.Parent then return false end local userId = player.UserId local removed = removeItemFromInventory(userId, itemName, amount) spawn(function() if player and player.Parent then pcall(function() InventoryUpdated:FireClient(player, "remove", itemName, amount) updateInventoryEvent:FireClient(player, playerInventories[userId] or {}) end) end end) return #removed >= 0 end GetItemCountFunc.OnServerInvoke = function(player, itemName) if not player or not player.Parent then return 0 end return getItemCount(player.UserId, itemName) end equipBrainrotEvent.OnServerEvent:Connect(function(player, brainrotName) if type(brainrotName) ~= "string" or brainrotName == "" then print("? Invalid brainrot name from " .. player.Name) return end local now = tick() if equipDebounce[player.UserId] and (now - equipDebounce[player.UserId]) < EQUIP_DEBOUNCE_TIME then print("? Equip debounced for " .. player.Name .. " (too fast)") return end equipDebounce[player.UserId] = now print("?? Equip request from " .. player.Name .. " for: " .. brainrotName) local inventory = playerInventories[player.UserId] if not inventory then warn("? No inventory found for " .. player.Name) return end local hasIt = false for _, item in ipairs(inventory) do if item.name == brainrotName then hasIt = true break end end if not hasIt then warn("? Player " .. player.Name .. " tried to equip brainrot they don't own: " .. brainrotName) return end local def = brainrotItems[brainrotName] if not def then warn("? Brainrot definition not found for: " .. brainrotName) return end equippedBrainrot[player.UserId] = brainrotName saveEquipped(player.UserId) playerTitleDisplayMain:FireAllClients(player.UserId, brainrotName, def.odds, def.titleColor or def.color) print("?? Fired SINGLE PlayerTitleDisplayEvent for:", player.Name, "->", brainrotName) equipBrainrotEvent:FireClient(player, brainrotName) print("? Player equipped brainrot:", player.Name, "->", brainrotName) end) equipBrainrotVisual.OnServerEvent:Connect(function(player, brainrotName, odds, color) print("?? Direct EquipBrainrotVisual from " .. player.Name .. " for: " .. brainrotName) equipBrainrotEvent:Fire(player, brainrotName) end) getEquippedFunction.OnServerInvoke = function(player) return equippedBrainrot[player.UserId] end game:BindToClose(function() print("?? Saving all player data before shutdown...") local savePromises = {} for userId, inventory in pairs(playerInventories) do local player = Players:GetPlayerByUserId(userId) if player and not alreadySaved[userId] then table.insert(savePromises, function() savePlayerInventory(player, true) saveEquipped(userId) alreadySaved[userId] = true end) end end for _, saveFunc in ipairs(savePromises) do spawn(saveFunc) end wait(5) print("? Shutdown save complete!") end) setupAutoAddIntegration() AdminCommandModule.init() _G.BrainrotInventoryItems = brainrotItems print("?? ENHANCED InventoryManager: Complete Auto-Add integration ready!") print("?? Updated: 2025-08-02 04:30:00 UTC") print("?? Updated by: Assistant") print("?? Key Features:") print(" - Enhanced auto-add processing with multiple fallback methods") print(" - Improved error handling and race condition prevention") print(" - Better timing for inventory updates and auto-add triggers") print(" - Mor