local ReplicatedStorage = game:GetService("ReplicatedStorage") local Players = game:GetService("Players") local DataStoreService = game:GetService("DataStoreService") local Remotes = ReplicatedStorage:WaitForChild("BrainrotSettingsRemotes") local SettingsStore = DataStoreService:GetDataStore("BrainrotSettings_v1") local defaultSettings = { AutoSave = 0, SkipBrainrots = 0, SkipCutscene = 0, SkipList = {}, SaveList = {} } local playerSettings = {} local saveDebounce = {} local saveQueued = {} local alreadySaved = {} local DEBOUNCE_TIME = 30 local function loadSettings(userId) local data pcall(function() data = SettingsStore:GetAsync(userId) end) if type(data) == "table" then for k, v in pairs(defaultSettings) do if data[k] == nil then data[k] = v end end return data else return table.clone(defaultSettings) end end local function saveSettings(userId, immediate) local data = playerSettings[userId] if not data then return end if alreadySaved[userId] then return end local now = os.clock() if not immediate then if saveDebounce[userId] and now - saveDebounce[userId] < DEBOUNCE_TIME then saveQueued[userId] = true return end end saveDebounce[userId] = now saveQueued[userId] = false pcall(function() SettingsStore:SetAsync(userId, data) end) alreadySaved[userId] = true end spawn(function() while true do wait(DEBOUNCE_TIME) for userId, queued in pairs(saveQueued) do if queued and not alreadySaved[userId] then saveSettings(userId, false) end end end end) Players.PlayerAdded:Connect(function(player) alreadySaved[player.UserId] = false local settings = loadSettings(player.UserId) playerSettings[player.UserId] = settings end) Players.PlayerRemoving:Connect(function(player) if not alreadySaved[player.UserId] then saveSettings(player.UserId, true) end playerSettings[player.UserId] = nil saveDebounce[player.UserId] = nil saveQueued[player.UserId] = nil alreadySaved[player.UserId] = true end) Remotes.RequestSettings.OnServerInvoke = function(player) return playerSettings[player.UserId] or table.clone(defaultSettings) end Remotes.UpdateSetting.OnServerEvent:Connect(function(player, key, value) local settings = playerSettings[player.UserId] if settings and defaultSettings[key] ~= nil then if key == "SkipBrainrots" and (type(value) ~= "number" or value < 0) then warn("Invalid skip value from", player.Name) return end settings[key] = value alreadySaved[player.UserId] = false saveSettings(player.UserId, false) end end)

