-- Script: ServerScriptService>DataStoreThrottleManager

 local DataStoreService = game:GetService("DataStoreService") local RunService = game:GetService("RunService") local DataStoreThrottleManager = {} local CONFIG = { MAX_REQUESTS_PER_MINUTE = 60, BATCH_SAVE_INTERVAL = 10, MAX_RETRIES = 3, RETRY_DELAY = 2, } local requestQueue = {} local requestTimestamps = {} local batchSaveQueue = {} local isProcessing = false local function cleanOldTimestamps() local now = os.time() for i = #requestTimestamps, 1, -1 do if now - requestTimestamps[i] >= 60 then table.remove(requestTimestamps, i) else break end end end local function canMakeRequest() cleanOldTimestamps() return #requestTimestamps < CONFIG.MAX_REQUESTS_PER_MINUTE end local function recordRequest() table.insert(requestTimestamps, os.time()) end function DataStoreThrottleManager.SafeCall(operation, ...) local args = {...} while not canMakeRequest() do warn("DataStore throttling: Waiting before making request...") wait(1) end recordRequest() for attempt = 1, CONFIG.MAX_RETRIES do local success, result = pcall(operation, unpack(args)) if success then return true, result else warn(string.format("DataStore operation failed (attempt %d/%d): %s", attempt, CONFIG.MAX_RETRIES, tostring(result))) if attempt < CONFIG.MAX_RETRIES then wait(CONFIG.RETRY_DELAY * attempt) end end end return false, "All retries failed" end function DataStoreThrottleManager.QueueBatchSave(dataStore, key, data) if not batchSaveQueue[dataStore] then batchSaveQueue[dataStore] = {} end batchSaveQueue[dataStore][key] = { data = data, timestamp = os.time() } end local function processBatchSaves() if isProcessing then return end isProcessing = true for dataStore, saves in pairs(batchSaveQueue) do for key, saveData in pairs(saves) do if canMakeRequest() then spawn(function() local success, result = DataStoreThrottleManager.SafeCall(function() return dataStore:SetAsync(key, saveData.data) end) if success then batchSaveQueue[dataStore][key] = nil print("? Batch saved:", key) else warn("? Batch save failed:", key) end end) else break end end end isProcessing = false end spawn(function() while true do wait(CONFIG.BATCH_SAVE_INTERVAL) processBatchSaves() end end) return DataStoreThrottleManager

-- Script: ServerScriptService>BrainrotTitleManager

 local ReplicatedStorage = game:GetService("ReplicatedStorage") local Players = game:GetService("Players") local function getOrCreateRemoteEvent(name) local existing = ReplicatedStorage:FindFirstChild(name) if existing then return existing end local event = Instance.new("RemoteEvent") event.Name = name event.Parent = ReplicatedStorage return event end local ShowBrainrotOnJLoEvent = getOrCreateRemoteEvent("ShowBrainrotOnJLoEvent") local PlayerTitleDisplayEvent = getOrCreateRemoteEvent("PlayerTitleDisplayEvent") local BrainrotDefinitions = require(ReplicatedStorage:WaitForChild("BrainrotDefinitions")) local activeBrainrots = {} local jloCurrentBrainrot = nil local function getPlayerByUserId(userId) return Players:GetPlayerByUserId(userId) end local function getBrainrotData(brainrotName) local brainrot = BrainrotDefinitions.Lookup[brainrotName] if not brainrot then return nil end return { name = brainrotName, odds = brainrot.odds, color = brainrot.titleColor or Color3.fromRGB(255, 255, 255), effects = brainrot.effects, vfxAsset = brainrot.vfxAsset } end local function clearPlayerTitle(userId) if not activeBrainrots[userId] then return end local player = getPlayerByUserId(userId) if player then PlayerTitleDisplayEvent:FireAllClients(userId, nil, nil, nil) end activeBrainrots[userId] = nil end local function applyBrainrotToPlayer(userId, brainrotName) if not userId or not brainrotName then return end local brainrotData = getBrainrotData(brainrotName) if not brainrotData then warn("Invalid brainrot:", brainrotName) return end activeBrainrots[userId] = { name = brainrotName, odds = brainrotData.odds, color = brainrotData.color, timestamp = tick() } PlayerTitleDisplayEvent:FireAllClients( userId, brainrotName, brainrotData.odds, brainrotData.color ) print("? Applied brainrot to userId:", userId, "->", brainrotName) end local function clearJLoTitle() if not jloCurrentBrainrot then return end local jlo = workspace:FindFirstChild("JLo") if jlo then ShowBrainrotOnJLoEvent:FireAllClients(jlo, nil, nil, nil) end jloCurrentBrainrot = nil end local function applyBrainrotToJLo(brainrotName) if not brainrotName then return end local brainrotData = getBrainrotData(brainrotName) if not brainrotData then warn("Invalid brainrot for JLo:", brainrotName) return end local jlo = workspace:FindFirstChild("JLo") if not jlo then warn("JLo model not found") return end jloCurrentBrainrot = { name = brainrotName, odds = brainrotData.odds, color = brainrotData.color, timestamp = tick() } ShowBrainrotOnJLoEvent:FireAllClients( jlo, brainrotName, brainrotData.odds, brainrotData.color ) print("? Applied brainrot to JLo:", brainrotName) end ShowBrainrotOnJLoEvent.OnServerEvent:Connect(function(player, brainrotName) if not player:GetAttribute("CanModifyJLo") then return end applyBrainrotToJLo(brainrotName) end) PlayerTitleDisplayEvent.OnServerEvent:Connect(function(player, targetUserId, brainrotName) if not player:GetAttribute("CanModifyTitles") then return end if brainrotName then applyBrainrotToPlayer(targetUserId, brainrotName) else clearPlayerTitle(targetUserId) end end) Players.PlayerRemoving:Connect(function(player) clearPlayerTitle(player.UserId) end) Players.PlayerAdded:Connect(function(player) if activeBrainrots[player.UserId] then local data = activeBrainrots[player.UserId] applyBrainrotToPlayer(player.UserId, data.name) end end) print("? Brainrot Title Manager Ready!")

-- Script: ServerScriptService>SafetyNetSystem

 local ReplicatedStorage = game:GetService("ReplicatedStorage") local Players = game:GetService("Players") local workspace = game:GetService("Workspace") local SafetyNetRemotes = ReplicatedStorage:FindFirstChild("SafetyNetRemotes") if not SafetyNetRemotes then SafetyNetRemotes = Instance.new("Folder") SafetyNetRemotes.Name = "SafetyNetRemotes" SafetyNetRemotes.Parent = ReplicatedStorage end local ShowBlackScreenEvent = SafetyNetRemotes:FindFirstChild("ShowBlackScreen") if not ShowBlackScreenEvent then ShowBlackScreenEvent = Instance.new("RemoteEvent") ShowBlackScreenEvent.Name = "ShowBlackScreen" ShowBlackScreenEvent.Parent = SafetyNetRemotes end local function getSpawnLocation() local spawnLocation = workspace:FindFirstChild("SpawnLocation") if spawnLocation then return spawnLocation.Position + Vector3.new(0, 5, 0) end return Vector3.new(0, 10, 0) end local function teleportToSpawn(player) local character = player.Character if not character then return end local humanoidRootPart = character:FindFirstChild("HumanoidRootPart") if not humanoidRootPart then return end local spawnPos = getSpawnLocation() ShowBlackScreenEvent:FireClient(player, true) wait(0.3) humanoidRootPart.CFrame = CFrame.new(spawnPos) local bodyVelocity = humanoidRootPart:FindFirstChild("BodyVelocity") if bodyVelocity then bodyVelocity:Destroy() end local bodyAngularVelocity = humanoidRootPart:FindFirstChild("BodyAngularVelocity") if bodyAngularVelocity then bodyAngularVelocity:Destroy() end if humanoidRootPart.AssemblyLinearVelocity then humanoidRootPart.AssemblyLinearVelocity = Vector3.new(0, 0, 0) end wait(0.5) ShowBlackScreenEvent:FireClient(player, false) print("??? " .. player.Name .. " was teleported back to spawn (out of bounds)") end local function setupSafetyNet() local safetyNet = workspace:FindFirstChild("SafetyNet") if not safetyNet then warn("?? SafetyNet not found in workspace! Please create a part named 'SafetyNet'") return end safetyNet.CanCollide = false safetyNet.Transparency = 0.8 safetyNet.Material = Enum.Material.ForceField if not safetyNet.BrickColor then safetyNet.BrickColor = BrickColor.new("Really red") end local debounce = {} safetyNet.Touched:Connect(function(hit) local character = hit.Parent local humanoid = character:FindFirstChildOfClass("Humanoid") if humanoid then local player = Players:GetPlayerFromCharacter(character) if player then if debounce[player.UserId] then return end debounce[player.UserId] = true spawn(function() teleportToSpawn(player) wait(2) debounce[player.UserId] = nil end) end end end) print("??? Safety net system initialized on: " .. safetyNet.Name) end setupSafetyNet() workspace.ChildAdded:Connect(function(child) if child.Name == "SafetyNet" then wait(0.1) setupSafetyNet() end end) print("??? Safety Net System Ready!")

-- Script: ServerScriptService>CombatZoneManager

 local ReplicatedStorage = game:GetService("ReplicatedStorage") local Players = game:GetService("Players") local RunService = game:GetService("RunService") local workspace = game:GetService("Workspace") local CombatRemotes = ReplicatedStorage:FindFirstChild("CombatRemotes") if not CombatRemotes then CombatRemotes = Instance.new("Folder") CombatRemotes.Name = "CombatRemotes" CombatRemotes.Parent = ReplicatedStorage end local CombatZoneStatusEvent = CombatRemotes:FindFirstChild("CombatZoneStatus") if not CombatZoneStatusEvent then CombatZoneStatusEvent = Instance.new("RemoteEvent") CombatZoneStatusEvent.Name = "CombatZoneStatus" CombatZoneStatusEvent.Parent = CombatRemotes end local ValidateDamageRemote = CombatRemotes:FindFirstChild("ValidateDamage") if not ValidateDamageRemote then ValidateDamageRemote = Instance.new("RemoteFunction") ValidateDamageRemote.Name = "ValidateDamage" ValidateDamageRemote.Parent = CombatRemotes end local playersInCombatZone = {} local combatZones = {} local function isPositionInCombatZone(position) for _, zone in pairs(combatZones) do if zone and zone.Parent then local zonePos = zone.Position local zoneSize = zone.Size local minX, maxX = zonePos.X - zoneSize.X/2, zonePos.X + zoneSize.X/2 local minY, maxY = zonePos.Y - zoneSize.Y/2, zonePos.Y + zoneSize.Y/2 local minZ, maxZ = zonePos.Z - zoneSize.Z/2, zonePos.Z + zoneSize.Z/2 if position.X >= minX and position.X <= maxX and position.Y >= minY and position.Y <= maxY and position.Z >= minZ and position.Z <= maxZ then return true end end end return false end local function findCombatZones() combatZones = {} local function searchForCombatZones(parent) for _, child in pairs(parent:GetChildren()) do if child:IsA("BasePart") and string.find(child.Name:lower(), "combatzone") then table.insert(combatZones, child) child.CanCollide = false child.Transparency = 0.7 child.Material = Enum.Material.ForceField child.BrickColor = BrickColor.new("Bright red") print("? Combat Zone registered:", child.Name) elseif child:IsA("Folder") or child:IsA("Model") then searchForCombatZones(child) end end end searchForCombatZones(workspace) print("?? Found", #combatZones, "combat zones") end local function updatePlayerCombatStatus() for _, player in pairs(Players:GetPlayers()) do if player.Character and player.Character:FindFirstChild("HumanoidRootPart") then local playerPos = player.Character.HumanoidRootPart.Position local inCombatZone = isPositionInCombatZone(playerPos) if playersInCombatZone[player.UserId] ~= inCombatZone then playersInCombatZone[player.UserId] = inCombatZone CombatZoneStatusEvent:FireClient(player, inCombatZone) if inCombatZone then print("?? " .. player.Name .. " entered combat zone") else print("??? " .. player.Name .. " left combat zone") end end end end end ValidateDamageRemote.OnServerInvoke = function(player, targetPlayer) local attackerInZone = playersInCombatZone[player.UserId] or false local targetInZone = playersInCombatZone[targetPlayer.UserId] or false local canDealDamage = attackerInZone and targetInZone if not canDealDamage then print("??? Damage blocked:", player.Name, "->", targetPlayer.Name, "(Zone status: attacker=" .. tostring(attackerInZone) .. ", target=" .. tostring(targetInZone) .. ")") end return canDealDamage end findCombatZones() local lastUpdate = 0 RunService.Heartbeat:Connect(function() local now = tick() if now - lastUpdate >= 0.5 then lastUpdate = now updatePlayerCombatStatus() end end) workspace.DescendantAdded:Connect(function(descendant) if descendant:IsA("BasePart") and string.find(descendant.Name:lower(), "combatzone") then wait(0.1) findCombatZones() end end) Players.PlayerRemoving:Connect(function(player) playersInCombatZone[player.UserId] = nil end) _G.IsPlayerInCombatZone = function(player) return playersInCombatZone[player.UserId] or false end _G.CanPlayerDealDamage = function(attacker, target) local attackerInZone = playersInCombatZone[attacker.UserId] or false local targetInZone = playersInCombatZone[target.UserId] or false return attackerInZone and targetInZone end print("?? Enhanced Combat Zone Manager - Damage Validation Ready!")

