 local ReplicatedStorage = game:GetService("ReplicatedStorage") local Players = game:GetService("Players") local CombatRemotes = ReplicatedStorage:WaitForChild("CombatRemotes") local ValidateCombatRemote = CombatRemotes:FindFirstChild("ValidateCombat") if not ValidateCombatRemote then ValidateCombatRemote = Instance.new("RemoteFunction") ValidateCombatRemote.Name = "ValidateCombat" ValidateCombatRemote.Parent = CombatRemotes end ValidateCombatRemote.OnServerInvoke = function(player) if _G.IsPlayerInCombatZone then return _G.IsPlayerInCombatZone(player) end return false end local function logCombatAttempt(player, allowed) local status = allowed and "ALLOWED" or "BLOCKED" print(string.format("??? Combat attempt by %s: %s", player.Name, status)) end _G.ValidatePlayerCombat = function(player) local allowed = _G.IsPlayerInCombatZone and _G.IsPlayerInCombatZone(player) or false logCombatAttempt(player, allowed) return allowed end print("??? Combat Zone Server Validation Ready!")

