 local ReplicatedStorage = game:GetService("ReplicatedStorage") local BrainrotDefinitions = require(ReplicatedStorage:WaitForChild("BrainrotDefinitions")) local ShowBrainrotOnJLoEvent = ReplicatedStorage:WaitForChild("ShowBrainrotOnJLoEvent") ShowBrainrotOnJLoEvent.OnServerEvent:Connect(function(player, brainrotName, odds, color) local brainrot = BrainrotDefinitions.Lookup[brainrotName] if not brainrot then return end local jloModel = workspace:FindFirstChild("JLo") if not jloModel then return end ShowBrainrotOnJLoEvent:FireClient(player, jloModel, brainrotName, brainrot.odds, brainrot.titleColor or Color3.fromRGB(255, 255, 255) ) end) print("? JLo Preview Handler Ready!")

-- Script: ServerScriptService>StartupRemotes

local ReplicatedStorage = game:GetService("ReplicatedStorage") print("?? STARTUP: Looking for existing folders and creating remotes...") local vfxFolder = ReplicatedStorage:WaitForChild("BrainrotVFX", 5) if not vfxFolder then warn("! WARNING: BrainrotVFX folder not found in ReplicatedStorage after 10 seconds!") return end print("? Found BrainrotVFX folder") local merchantRemotes = ReplicatedStorage:FindFirstChild("MerchantRemotes") if not merchantRemotes then merchantRemotes = Instance.new("Folder") merchantRemotes.Name = "MerchantRemotes" merchantRemotes.Parent = ReplicatedStorage print("? Created MerchantRemotes folder") end local function initializeBadgeSystem() local badgeRemotes = ReplicatedStorage:FindFirstChild("BadgeRemotes") if not badgeRemotes then badgeRemotes = Instance.new("Folder") badgeRemotes.Name = "BadgeRemotes" badgeRemotes.Parent = ReplicatedStorage end local badgeSystemReady = Instance.new("BoolValue") badgeSystemReady.Name = "BadgeSystemReady" badgeSystemReady.Value = true badgeSystemReady.Parent = badgeRemotes end spawn(initializeBadgeSystem) local merchantEvents = { "OpenShop", "AddIngredient", "CraftItem", "CloseShop" } for _, eventName in ipairs(merchantEvents) do if not merchantRemotes:FindFirstChild(eventName) then local newEvent = Instance.new("RemoteEvent") newEvent.Name = eventName newEvent.Parent = merchantRemotes print("? Created MerchantRemote: " .. eventName) end end local badgeRemotes = ReplicatedStorage:FindFirstChild("BadgeRemotes") if not badgeRemotes then badgeRemotes = Instance.new("Folder") badgeRemotes.Name = "BadgeRemotes" badgeRemotes.Parent = ReplicatedStorage print("? Created BadgeRemotes folder") end local badgeEvents = { "UpdateBadges", "EquipBadge", "UnequipBadge" } for _, eventName in ipairs(badgeEvents) do if not badgeRemotes:FindFirstChild(eventName) then local newEvent = Instance.new("RemoteEvent") newEvent.Name = eventName newEvent.Parent = badgeRemotes print("? Created BadgeRemote: " .. eventName) end end local badgeFunctions = { "GetBadges", "GetEquippedBadges" } for _, functionName in ipairs(badgeFunctions) do if not badgeRemotes:FindFirstChild(functionName) then local newFunction = Instance.new("RemoteFunction") newFunction.Name = functionName newFunction.Parent = badgeRemotes print("? Created BadgeFunction: " .. functionName) end end if not ReplicatedStorage:FindFirstChild("LuckBoostEvent") then local luckBoostEvent = Instance.new("RemoteEvent") luckBoostEvent.Name = "LuckBoostEvent" luckBoostEvent.Parent = ReplicatedStorage print("? Created LuckBoostEvent") end local soundsFolder = ReplicatedStorage:FindFirstChild("BrainrotSounds") if not soundsFolder then soundsFolder = Instance.new("Folder") soundsFolder.Name = "BrainrotSounds" soundsFolder.Parent = ReplicatedStorage print("? Created BrainrotSounds folder") end if not ReplicatedStorage:FindFirstChild("EquipBrainrotVisual") then local equipBrainrotVisual = Instance.new("RemoteEvent") equipBrainrotVisual.Name = "EquipBrainrotVisual" equipBrainrotVisual.Parent = ReplicatedStorage print("? Created EquipBrainrotVisual RemoteEvent") end if not ReplicatedStorage:FindFirstChild("ShowBrainrotOnJLoEvent") then local showBrainrotOnJLo = Instance.new("RemoteEvent") showBrainrotOnJLo.Name = "ShowBrainrotOnJLoEvent" showBrainrotOnJLo.Parent = ReplicatedStorage print("? Created ShowBrainrotOnJLoEvent RemoteEvent") end if not ReplicatedStorage:FindFirstChild("EquipBrainrotTitle") then local equipBrainrotTitle = Instance.new("RemoteEvent") equipBrainrotTitle.Name = "EquipBrainrotTitle" equipBrainrotTitle.Parent = ReplicatedStorage print("? Created EquipBrainrotTitle RemoteEvent") end print("?? STARTUP: All systems initialized successfully!") wait(1)

-- Script: ServerScriptService>BrainrotServer

local ReplicatedStorage = game:GetService("ReplicatedStorage") local Players = game:GetService("Players") local equipBrainrotTitle = ReplicatedStorage:WaitForChild("EquipBrainrotTitle") local equipBrainrotVisual = ReplicatedStorage:WaitForChild("EquipBrainrotVisual") local BrainrotDefinitions = require(ReplicatedStorage:WaitForChild("BrainrotDefinitions")) equipBrainrotTitle.OnServerEvent:Connect(function(player, brainrotName) local brainrot = BrainrotDefinitions.Lookup[brainrotName] if not brainrot then return end equipBrainrotVisual:FireAllClients(player, brainrotName, brainrot.odds, brainrot.titleColor) end)

